 package main

 import (
 	"context"
 	"log"
 	"os"
 	"os/signal"
 	"path/filepath"
 	"syscall"

 	"github.com/company4312/copilot-telegram-bot/internal/agent"
 	"github.com/company4312/copilot-telegram-bot/internal/bot"
 	"github.com/company4312/copilot-telegram-bot/internal/store"
 )

 func main() {
 	token := os.Getenv("TELEGRAM_BOT_TOKEN")
 	if token == "" {
 		log.Fatal("TELEGRAM_BOT_TOKEN environment variable is required")
 	}

 	// Ensure the data directory exists.
 	dataDir := "data"
 	if err := os.MkdirAll(dataDir, 0o750); err != nil {
 		log.Fatalf("create data dir: %v", err)
 	}

 	// Initialize the session store.
 	dbPath := filepath.Join(dataDir, "bot.db")
 	s, err := store.New(dbPath)
 	if err != nil {
 		log.Fatalf("open database: %v", err)
 	}
 	defer s.Close()

 	// Initialize and start the Copilot agent.
 	configDir := filepath.Join(dataDir, "sessions")
 	if err := os.MkdirAll(configDir, 0o750); err != nil {
 		log.Fatalf("create config dir: %v", err)
 	}

 	a := agent.New(s, configDir)
 	ctx, cancel := context.WithCancel(context.Background())
 	defer cancel()

 	if err := a.Start(ctx); err != nil {
 		log.Fatalf("start copilot agent: %v", err)
 	}
 	defer a.Stop()

 	// Initialize the Telegram bot.
 	b, err := bot.New(token, a)
 	if err != nil {
 		log.Fatalf("init telegram bot: %v", err)
 	}

 	// Graceful shutdown on SIGINT/SIGTERM.
 	sigCh := make(chan os.Signal, 1)
 	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
 	go func() {
 		sig := <-sigCh
 		log.Printf("received %s, shutting down…", sig)
 		cancel()
 	}()

 	log.Println("Bot is running. Press Ctrl+C to stop.")
 	if err := b.Run(ctx); err != nil {
 		log.Fatalf("bot error: %v", err)
 	}
 	log.Println("Shutdown complete.")
 }

