 func New(s *store.Store, configDir string) *Agent {
 	client := copilot.NewClient(&copilot.ClientOptions{
 		LogLevel: "error",
 	})
 	return &Agent{
 		client:    client,
 		store:     s,
 		configDir: configDir,
 		sessions:  make(map[int64]*copilot.Session),
 	}
 }

