 func (a *Agent) Stop() error {
 	a.mu.Lock()
 	defer a.mu.Unlock()
 	for chatID, session := range a.sessions {
 		session.Destroy()
 		delete(a.sessions, chatID)
 	}
 	return a.client.Stop()
 }

 // SendMessage sends a user message within the Copilot session for the given chat
 // and returns the assistant's full response text.
 func (a *Agent) SendMessage(ctx context.Context, chatID int64, text string) (string, error) {
 	session, err := a.getOrCreateSession(ctx, chatID)
 	if err != nil {
 		return "", fmt.Errorf("session setup: %w", err)
 	}

 	response, err := a.sendAndWait(ctx, session, text)
 	if err != nil {
 		// If send fails, the session may be stale — clear it and retry once.
 		a.clearSession(chatID)
 		session, err = a.getOrCreateSession(ctx, chatID)
 		if err != nil {
 			return "", fmt.Errorf("session retry: %w", err)
 		}
 		response, err = a.sendAndWait(ctx, session, text)
 		if err != nil {
 			return "", fmt.Errorf("send message: %w", err)
 		}
 	}

 	return response, nil
 }

 // sendAndWait sends a prompt on the session and blocks until "session.idle".
 func (a *Agent) sendAndWait(ctx context.Context, session *copilot.Session, text string) (string, error) {
 	var (
 		response string
 		done     = make(chan struct{})
 		once     sync.Once
 	)

 	unsubscribe := session.On(func(event copilot.SessionEvent) {
 		switch event.Type {
 		case "assistant.message":
 			if event.Data.Content != nil {
 				response = *event.Data.Content
 			}
 		case "session.idle":
 			once.Do(func() { close(done) })
 		}
 	})
 	defer unsubscribe()

 	if _, err := session.Send(ctx, copilot.MessageOptions{Prompt: text}); err != nil {
 		return "", err
 	}

 	select {
 	case <-done:
 		return response, nil
 	case <-ctx.Done():
 		return response, ctx.Err()
 	}
