 	defer a.mu.Unlock()

 	if session, ok := a.sessions[chatID]; ok {
 		return session, nil
 	}

 	// Try to resume a persisted session.
 	sessionID, err := a.store.GetSessionID(chatID)
 	if err != nil {
 		return nil, err
 	}

 	if sessionID != "" {
 		session, err := a.client.ResumeSession(ctx, sessionID, &copilot.ResumeSessionConfig{
 			OnPermissionRequest: copilot.PermissionHandler.ApproveAll,
 			ConfigDir:           a.configDir,
