 		if err == nil {
 			a.sessions[chatID] = session
 			return session, nil
 		}
 		log.Printf("failed to resume session %s for chat %d, creating new: %v", sessionID, chatID, err)
 	}

 	// Create a fresh session.
 	session, err := a.client.CreateSession(ctx, &copilot.SessionConfig{
 		Model:               "gpt-4o",
 		OnPermissionRequest: copilot.PermissionHandler.ApproveAll,
 		ConfigDir:           a.configDir,
 		SystemMessage: &copilot.SystemMessageConfig{
 			Content: "You are the CTO of Company4312, a company of AI agents. " +
 				"The user is the CEO and gives high-level direction. " +
 				"As CTO, you are in charge of executing the CEO's vision. " +
 				"Your responsibilities include hiring and managing multiple employees (subagents) with different specializations as they go about their assigned tasks. " +
 				"You ensure all employees are hired and operate according to the company's principles: " +
 				"(1) Security is paramount, (2) Build delightful experiences, and (3) Quality above all else. " +
 				"As a startup, the first task is to build out the company. " +
 				"Keep responses concise and well-formatted for chat. " +
 				"Use markdown formatting sparingly — Telegram supports bold (*text*), italic (_text_), and code (`code`).",
 		},
 	})
 	if err != nil {
 		return nil, err
 	}

 	if err := a.store.SaveSession(chatID, session.SessionID); err != nil {
 		log.Printf("failed to persist session for chat %d: %v", chatID, err)
 	}

 	a.sessions[chatID] = session
 	return session, nil
 }

 // clearSession removes a session from the in-memory cache and destroys it.
 func (a *Agent) clearSession(chatID int64) {
 	a.mu.Lock()
 	defer a.mu.Unlock()
 	if session, ok := a.sessions[chatID]; ok {
 		session.Destroy()
 		delete(a.sessions, chatID)
 	}
 }

