 package store

 import (
 	"database/sql"
 	"time"

 	_ "modernc.org/sqlite"
 )

 // Store manages chat-to-session mappings in a local SQLite database.
 type Store struct {
 	db *sql.DB
 }

 // New opens (or creates) a SQLite database at dbPath and ensures the schema exists.
 func New(dbPath string) (*Store, error) {
 	db, err := sql.Open("sqlite", dbPath)
 	if err != nil {
 		return nil, err
 	}

 	// Enable WAL mode for better concurrent read performance.
 	if _, err := db.Exec("PRAGMA journal_mode=WAL"); err != nil {
 		db.Close()
 		return nil, err
 	}

 	const schema = `
 	CREATE TABLE IF NOT EXISTS sessions (
 		chat_id    INTEGER PRIMARY KEY,
 		session_id TEXT    NOT NULL,
 		created_at TEXT    NOT NULL,
 		updated_at TEXT    NOT NULL
 	)`
 	if _, err := db.Exec(schema); err != nil {
 		db.Close()
 		return nil, err
 	}

 	return &Store{db: db}, nil
 }

 // GetSessionID returns the Copilot session ID for a Telegram chat, or "" if none exists.
 func (s *Store) GetSessionID(chatID int64) (string, error) {
 	var sessionID string
 	err := s.db.QueryRow("SELECT session_id FROM sessions WHERE chat_id = ?", chatID).Scan(&sessionID)
 	if err == sql.ErrNoRows {
 		return "", nil
 	}
 	return sessionID, err
 }

 // SaveSession upserts a chat-to-session mapping.
 func (s *Store) SaveSession(chatID int64, sessionID string) error {
 	now := time.Now().UTC().Format(time.RFC3339)
 	_, err := s.db.Exec(`
 		INSERT INTO sessions (chat_id, session_id, created_at, updated_at)
 		VALUES (?, ?, ?, ?)
 		ON CONFLICT(chat_id) DO UPDATE SET session_id = excluded.session_id, updated_at = excluded.updated_at
 	`, chatID, sessionID, now, now)
 	return err
 }

 // DeleteSession removes the session mapping for a chat.
 func (s *Store) DeleteSession(chatID int64) error {
 	_, err := s.db.Exec("DELETE FROM sessions WHERE chat_id = ?", chatID)
 	return err
 }

 // Close closes the database connection.
 func (s *Store) Close() error {
 	return s.db.Close()
 }

